#include <stdio.h>

void solve() {
    long long int n, ans = 0;
    scanf("%lld", &n);

    long long int ar[n + 1][n + 1];
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            scanf("%lld", &ar[i][j]);
        }
    }

    long long int dp[n + 1][n + 1];
    for (int j = 1; j <= n; j++) {
        dp[n][j] = ar[n][j];
    }

    for (int i = n - 1; i >= 1; i--) {
        for (int j = 1; j <= i; j++) {
            dp[i][j] = ar[i][j] + (dp[i + 1][j] > dp[i + 1][j + 1] ? dp[i + 1][j] : dp[i + 1][j + 1]);
        }
    }

    printf("%lld\n", dp[1][1]);
}

int main() {
    long long int t = 1;
    scanf("%lld", &t);
    for (int it = 1; it <= t; it++) {
        solve();
    }
    return 0;
